import React from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';
import { FEATURE_CARDS } from '../utils/constants';
import '../styles/dashboard.css';

function FeatureCard({ card }) {
  const navigate = useNavigate();

  return (
    <div
      className="dash-card"
      onClick={() => navigate(card.path)}
      role="button"
      tabIndex={0}
      aria-label={`Open ${card.title}`}
      onKeyDown={(e) => e.key === 'Enter' && navigate(card.path)}
    >
      <div
        className="dash-card__icon-wrap"
        style={{ background: `${card.color}18` }}
      >
        <span className="dash-card__icon">{card.icon}</span>
      </div>
      <div className="dash-card__body">
        <h3 className="dash-card__title">{card.title}</h3>
        <p className="dash-card__desc">{card.description}</p>
      </div>
      <div className="dash-card__footer">
        {card.available ? (
          <span className="badge badge--active" style={{ background: card.color }}>
            Open →
          </span>
        ) : (
          <span className="badge badge--soon">Coming Soon</span>
        )}
      </div>
    </div>
  );
}

function StatsBar({ user }) {
  return (
    <div className="stats-bar">
      <div className="stats-bar__item">
        <span className="stats-bar__value">0</span>
        <span className="stats-bar__label">Resumes Analysed</span>
      </div>
      <div className="stats-bar__divider" />
      <div className="stats-bar__item">
        <span className="stats-bar__value">0</span>
        <span className="stats-bar__label">Interviews Practiced</span>
      </div>
      <div className="stats-bar__divider" />
      <div className="stats-bar__item">
        <span className="stats-bar__value">0</span>
        <span className="stats-bar__label">Problems Solved</span>
      </div>
      <div className="stats-bar__divider" />
      <div className="stats-bar__item">
        <span className="stats-bar__value" style={{ color: '#2563EB' }}>
          {user?.role || 'STUDENT'}
        </span>
        <span className="stats-bar__label">Account Type</span>
      </div>
    </div>
  );
}

function DashboardPage() {
  const { user } = useAuth();
  const firstName = user?.fullName?.split(' ')[0] || 'Student';
  const today = new Date().toLocaleDateString('en-US', {
    weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
  });

  return (
    <div className="dashboard">

      {/* Welcome banner */}
      <section className="dash-welcome">
        <div className="dash-welcome__text">
          <p className="dash-welcome__date">{today}</p>
          <h1 className="dash-welcome__heading">
            Welcome back, <span className="dash-welcome__name">{firstName}</span> 👋
          </h1>
          <p className="dash-welcome__sub">
            Your AI-powered placement preparation dashboard. Choose a module below to get started.
          </p>
        </div>
        <div className="dash-welcome__avatar">
          <div className="avatar-circle">
            {user?.fullName?.charAt(0)?.toUpperCase() || 'S'}
          </div>
        </div>
      </section>

      {/* Stats */}
      <StatsBar user={user} />

      {/* Feature cards */}
      <section className="dash-features">
        <h2 className="dash-features__heading">AI Modules</h2>
        <div className="dash-features__grid">
          {FEATURE_CARDS.map((card) => (
            <FeatureCard key={card.id} card={card} />
          ))}
        </div>
      </section>

      {/* Quick tips */}
      <section className="dash-tips">
        <h2 className="dash-tips__heading">Quick Tips to Get Started</h2>
        <div className="dash-tips__list">
          {[
            { icon: '📄', tip: 'Upload your resume to get an AI score and improvement suggestions.' },
            { icon: '💻', tip: 'Solve at least 2 coding problems daily to build consistency.' },
            { icon: '🎤', tip: 'Complete a mock interview session before applying to companies.' },
            { icon: '📊', tip: 'Run a skill gap analysis to identify what to learn next.' },
          ].map((item, i) => (
            <div key={i} className="tip-item">
              <span className="tip-item__icon">{item.icon}</span>
              <p className="tip-item__text">{item.tip}</p>
            </div>
          ))}
        </div>
      </section>

    </div>
  );
}

export default DashboardPage;
